minimalFix:
To fix the stale closure, the `useCallback` for `debouncedSearch` must include all its dependencies that can change over time. Specifically, `query` and `delayMs` must be added to the dependency array. The React state setters (`setResults`, `setIsLoading`, `setError`) are stable and don't strictly need to be added in most React 18+ scenarios, but adding them for exhaustive dependency adherence is a safe practice.

```typescript
// src/hooks/useSearchDebounce.ts
import { useState, useEffect, useRef, useCallback } from 'react';
import { SearchResult, searchDocuments } from '../services/searchService';

export function useSearchDebounce(query: string, delayMs: number = 300) {
  const [results, setResults] = useState<SearchResult[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const timerRef = useRef<ReturnType<typeof setTimeout> | null>(null);

  const debouncedSearch = useCallback(() => {
    if (timerRef.current) clearTimeout(timerRef.current);

    if (!query.trim()) {
      setResults([]);
      setIsLoading(false);
      return;
    }

    setIsLoading(true);
    timerRef.current = setTimeout(async () => {
      try {
        const found = await searchDocuments(query);
        setResults(found);
        setError(null);
      } catch (err) {
        setError(err instanceof Error ? err.message : 'Search failed');
        setResults([]);
      } finally {
        setIsLoading(false);
      }
    }, delayMs);
  }, [query, delayMs, setResults, setIsLoading, setError]); // FIX: Added query, delayMs, and state setters to dependencies

  useEffect(() => {
    debouncedSearch();
    return () => {
      if (timerRef.current) clearTimeout(timerRef.current);
    };
  }, [query, debouncedSearch]);

  return { results, isLoading, error };
}
